#include <stdio.h>

int main() {
    int T, Y;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &Y) != 1) break;
        int profit = Y * 200 - 5000;
        if (profit >= 0) printf("%d\n", profit);
        else printf("-1\n");
    }
    return 0;
}

